+
+    // -- Report --
+
+    #[test]
+    fn report_all_healthy() {
+        let specs = canonical_channel_specs();
+        let states = BTreeMap::new();
+        let report = generate_report(&specs, &states, epoch(1));
+        assert!(report.gate_pass);
+        assert_eq!(report.total_violations, 0);
