+        // Emit 1000 items out of 100_000 capacity.
+        for _ in 0..1000 {
+            state.emit(spec, 0).unwrap();
+            state.drain_one();
+        }
+        states.insert(spec.channel_id.clone(), state);
+
+        let report = generate_report(&specs, &states, epoch(1));
+        let entry = report
+            .channels
+            .iter()
+            .find(|e| e.channel_id == "ch-decision-ledger")
+            .unwrap();
