+        assert!(dag.has_path(
+            &"environment_load".to_string(),
+            &"latency_outcome".to_string()
+        ));
+    }
+
+    #[test]
+    fn test_lane_dag_report_content() {
+        let dag = build_lane_decision_dag().unwrap();
+        let report = dag.report();
